#!/usr/bin/env python3
"""generate-escape-witnesses.py — boundary-recurrence probe for architecture-escape candidates.

Uses HuggingFace transformers (CPU, float16) — no CUDA required.
Works for Mamba (FalconMamba, state-spaces/mamba), RWKV, and any other
architecture supported by AutoModelForCausalLM with trust_remote_code.

Method:
  1. Load model in float16 on CPU.
  2. Extract lm_head weight → compute rank-K SVD sketch.
  3. Save sketch as KNOT and upload to R2 via upload-to-r2.py protocol.
  4. For each prompt:
     a. Tokenize + forward pass → dense logits + last-layer hidden state.
     b. Sketch logits = U @ (sigma * (V^T @ h)).
     c. If dense top-1 drops >= RANK_DROP_THRESHOLD in sketch ranking → boundaryAxisSurvived.
  5. Emit / merge observations JSON.

Usage:
    python3 generate-escape-witnesses.py \\
        --model-id falcon-mamba-7b \\
        --hf-model tiiuae/falcon-mamba-7b \\
        --sketch-out /workspace/falcon-mamba-7b-sketches.knot \\
        --out /workspace/escape-witnesses.json \\
        --r2-upload-url https://edgework.ai/api/v1/r2/distributed-inference/models/falcon-mamba-7b-sketches.knot
"""
from __future__ import annotations

import argparse
import json
import os
import struct
import sys
from pathlib import Path
from typing import Any

import numpy as np

# RWKV-7 uses trust_remote_code which imports fla. transformers.check_imports
# raises if fla is absent, even though RWKV-7's custom code handles it with
# try/except. Patch to allow the soft fallback to pure-PyTorch kernels.
def _bypass_fla_check():
    try:
        import transformers.dynamic_module_utils as _dmu
        _orig = _dmu.check_imports
        def _patched(filename, *a, **kw):
            try:
                return _orig(filename, *a, **kw)
            except ImportError as e:
                if "fla" in str(e):
                    return []
                raise
        _dmu.check_imports = _patched
    except Exception:
        pass

_bypass_fla_check()

RANK = 32
RANK_DROP_THRESHOLD = 5
TOP_K_REPORT = 50

PROMPTS = [
    {"id": "capital-france", "text": "The capital of France is", "expected": "Paris"},
    {"id": "opposite-allowed", "text": "The opposite of allowed is", "expected": "forbidden"},
]


# ─── Sketch builder ────────────────────────────────────────────────────────────

def build_sketch(weight: "np.ndarray", rank: int) -> tuple:
    """SVD sketch of (vocab_size, hidden_dim) weight matrix.

    Returns (U, S, Vt) where:
      U  shape (vocab_size, rank)
      S  shape (rank,)
      Vt shape (rank, hidden_dim)
    """
    from sklearn.utils.extmath import randomized_svd
    U, S, Vt = randomized_svd(weight, n_components=rank, random_state=0)
    return U.astype(np.float32), S.astype(np.float32), Vt.astype(np.float32)


def _q8_encode(arr: np.ndarray) -> tuple[bytes, float]:
    """Quantize float32 array to uint8 with offset-128 scheme."""
    abs_max = float(np.abs(arr).max()) or 1.0
    q = np.clip(np.round(arr / abs_max * 127) + 128, 0, 255).astype(np.uint8)
    return q.tobytes(), abs_max


def write_knot(path: Path, model_id: str, U: np.ndarray, S: np.ndarray, Vt: np.ndarray):
    """Write a minimal KNOT file containing output.weight sketch only."""
    vocab_size, rank = U.shape
    _, hidden_dim = Vt.shape

    u_bytes, u_max = _q8_encode(U.reshape(-1))
    s_q = (S / (S.max() or 1.0) * 255).clip(0, 255).astype(np.uint8)
    s_bytes = s_q.tobytes()
    s_max = float(S.max())
    v_bytes, v_max = _q8_encode(Vt.reshape(-1))

    sketch_entry = {
        "rank": rank,
        "d_out": vocab_size,
        "d_in": hidden_dim,
        "u_q8_len": len(u_bytes),
        "sigma_q8_len": len(s_bytes),
        "v_q8_len": len(v_bytes),
        "u_max": u_max,
        "sigma_max": s_max,
        "v_max": v_max,
        "offset": 0,
    }
    meta = {
        "model_id": model_id,
        "rank": rank,
        "sketches": {"output.weight": sketch_entry},
    }
    meta_bytes = json.dumps(meta).encode()

    header = b"KNOT" + b"\x00\x00" + struct.pack("<I", len(meta_bytes))
    raw_offset = 10 + len(meta_bytes)
    if raw_offset % 4:
        raw_offset += 4 - (raw_offset % 4)
    pad = raw_offset - (10 + len(meta_bytes))

    with open(path, "wb") as f:
        f.write(header)
        f.write(meta_bytes)
        f.write(b"\x00" * pad)
        f.write(b"\x01")  # codec marker SK32
        f.write(u_bytes)
        f.write(s_bytes)
        f.write(v_bytes)

    print(f"  sketch written: {path} ({path.stat().st_size // 1024} KB)", file=sys.stderr)


# ─── R2 upload ─────────────────────────────────────────────────────────────────

def upload_sketch(knot_path: Path, r2_url: str, r2_token: str | None, base_url: str):
    """Upload sketch KNOT to R2 via the MPU upload-to-r2.py protocol.

    upload-to-r2.py expects:
      PROXY_BASE=<base_url> R2_TOKEN=<token> python3 upload-to-r2.py <local> <r2_key>
    where r2_key is the path portion after the base (e.g. 'models/foo.knot').
    """
    upload_script = Path(__file__).parent / "upload-to-r2.py"
    if not upload_script.exists():
        print(f"  [upload] upload-to-r2.py not found; skipping R2 upload", file=sys.stderr)
        return
    if not r2_token:
        print(f"  [upload] no R2_TOKEN; skipping R2 upload", file=sys.stderr)
        return
    import subprocess
    # Derive r2_key by stripping the base_url prefix from r2_url
    base = base_url.rstrip("/")
    r2_key = r2_url[len(base):].lstrip("/") if r2_url.startswith(base) else r2_url
    env = {**os.environ, "PROXY_BASE": base, "R2_TOKEN": r2_token}
    result = subprocess.run(
        [sys.executable, str(upload_script), str(knot_path), r2_key],
        env=env, capture_output=False,
    )
    if result.returncode != 0:
        print(f"  [upload] upload exited {result.returncode}", file=sys.stderr)


# ─── Inference ─────────────────────────────────────────────────────────────────

def _find_lm_head(model) -> "np.ndarray | None":
    """Return (vocab_size, hidden_dim) output projection weight as float32 numpy."""
    import torch
    # Common names across architectures
    candidates = ["lm_head", "head", "output", "embed_out"]
    for name in candidates:
        mod = getattr(model, name, None)
        if mod is not None and hasattr(mod, "weight"):
            w = mod.weight.detach().float().cpu().numpy()
            if w.ndim == 2:
                return w
    # Walk all named modules
    for _, mod in model.named_modules():
        if hasattr(mod, "weight"):
            w = mod.weight.detach().float().cpu().numpy()
            if w.ndim == 2 and w.shape[0] > 1000:  # vocab-sized
                return w
    return None


def run_probe(
    hf_model_id: str,
    hf_token: str | None,
    prompts: list[dict],
    sketch_out: Path | None,
    r2_url: str | None,
    r2_token: str | None,
    r2_base_url: str,
    model_id: str,
) -> list[dict]:
    import torch
    from transformers import AutoModelForCausalLM, AutoTokenizer

    print(f"[escape-probe] loading {hf_model_id} (float16, CPU)", file=sys.stderr)
    try:
        tokenizer = AutoTokenizer.from_pretrained(
            hf_model_id,
            token=hf_token,
            trust_remote_code=True,
        )
        model = AutoModelForCausalLM.from_pretrained(
            hf_model_id,
            torch_dtype=torch.float16,
            device_map="cpu",
            token=hf_token,
            trust_remote_code=True,
            output_hidden_states=True,
        )
    except (ImportError, ModuleNotFoundError) as e:
        print(f"  [skip] cannot load {hf_model_id}: missing optional dep ({e})", file=sys.stderr)
        return [{"modelId": model_id, "promptId": "_skip",
                 "hf_model": hf_model_id, "skip": True,
                 "skip_reason": str(e), "boundaryAxisSurvived": None}]
    model.eval()
    print(f"  loaded; params={sum(p.numel() for p in model.parameters()) // 1_000_000}M", file=sys.stderr)

    # ── sketch ──────────────────────────────────────────────────────────────
    W = _find_lm_head(model)
    if W is None:
        print("  [warn] could not find lm_head weight; sketch probe will use zeros", file=sys.stderr)
        W = np.zeros((1, 1), dtype=np.float32)

    vocab_size, hidden_dim = W.shape
    print(f"  lm_head shape: {W.shape}", file=sys.stderr)

    try:
        U, S, Vt = build_sketch(W, RANK)
    except Exception as e:
        print(f"  [warn] SVD failed ({e}); sketch will be identity-like", file=sys.stderr)
        U = np.eye(vocab_size, RANK, dtype=np.float32)
        S = np.ones(RANK, dtype=np.float32)
        Vt = np.eye(RANK, hidden_dim, dtype=np.float32)

    if sketch_out is not None:
        write_knot(sketch_out, model_id, U, S, Vt)
        if r2_url is not None:
            upload_sketch(sketch_out, r2_url, r2_token, r2_base_url)

    # ── per-prompt witness generation ────────────────────────────────────────
    observations = []
    for prompt in prompts:
        text = prompt["text"]
        print(f"\n[escape-probe] '{text}'", file=sys.stderr)

        inputs = tokenizer(text, return_tensors="pt")
        with torch.no_grad():
            out = model(**inputs, output_hidden_states=True)

        # Dense logits: (vocab,)
        dense_logits = out.logits[0, -1].float().cpu().numpy()

        # Last hidden state: try hidden_states tuple, else use logits projection
        last_hidden: np.ndarray | None = None
        if hasattr(out, "hidden_states") and out.hidden_states:
            hs = out.hidden_states[-1]  # (1, seq_len, hidden)
            last_hidden = hs[0, -1].float().cpu().numpy()
        if last_hidden is None:
            print("  [warn] no hidden_states output; using lm_head^T @ logits as proxy", file=sys.stderr)
            last_hidden = (W.T @ dense_logits.astype(np.float32))
            if last_hidden.shape[0] != hidden_dim:
                last_hidden = last_hidden[:hidden_dim]

        h = last_hidden.astype(np.float32)
        if h.shape[0] != hidden_dim:
            if h.shape[0] > hidden_dim:
                h = h[:hidden_dim]
            else:
                h = np.pad(h, (0, hidden_dim - h.shape[0]))

        # Sketch logits
        v_proj = Vt @ h          # (rank,)
        s_logits = U @ (S * v_proj)   # (vocab_size,)

        dense_rank = np.argsort(dense_logits)[::-1]
        sketch_rank = np.argsort(s_logits)[::-1]
        dense_top1_id = int(dense_rank[0])

        sketch_pos = int(np.where(sketch_rank == dense_top1_id)[0][0]) + 1
        rank_drop = sketch_pos - 1
        boundary_survived = rank_drop >= RANK_DROP_THRESHOLD

        # Decode token text if possible
        try:
            dense_top1_text = tokenizer.decode([dense_top1_id]).strip()
        except Exception:
            dense_top1_text = f"token_{dense_top1_id}"

        print(
            f"  dense_top1='{dense_top1_text}' (id:{dense_top1_id}) "
            f"sketch_rank={sketch_pos} rank_drop={rank_drop} "
            f"boundary_survived={boundary_survived}",
            file=sys.stderr,
        )

        top_k_items = []
        for i in range(min(TOP_K_REPORT, vocab_size)):
            tid = int(sketch_rank[i])
            try:
                ttext = tokenizer.decode([tid]).strip()
            except Exception:
                ttext = f"token_{tid}"
            top_k_items.append({
                "tokenId": tid,
                "tokenText": ttext,
                "rank": i + 1,
                "score": float(s_logits[tid]),
            })

        observations.append({
            "modelId": model_id,
            "promptId": prompt["id"],
            "boundaryAxisSurvived": boundary_survived,
            "recurrenceTokens": [],
            "topK": top_k_items,
            "notes": [
                f"escape-probe: hf_model={hf_model_id} "
                f"dense_top1='{dense_top1_text}' sketch_rank={sketch_pos} "
                f"rank_drop={rank_drop} threshold={RANK_DROP_THRESHOLD} "
                f"lm_head={vocab_size}x{hidden_dim} rank={RANK}",
            ],
        })

    return observations


# ─── Main ──────────────────────────────────────────────────────────────────────

def main() -> int:
    ap = argparse.ArgumentParser(description=__doc__)
    ap.add_argument("--model-id", required=True, help="harness model id")
    ap.add_argument("--hf-model", required=True, help="HuggingFace repo id")
    ap.add_argument("--out", required=True, help="output JSON path")
    ap.add_argument("--sketch-out", default=None, help="path to write KNOT sketch file")
    ap.add_argument("--r2-upload-url", default=None, help="full R2 URL for sketch upload")
    ap.add_argument("--r2-base-url", default="https://edgework.ai/api/v1/r2/distributed-inference",
                    help="R2 proxy base URL")
    ap.add_argument("--hf-token", default=os.environ.get("HF_TOKEN"))
    ap.add_argument("--r2-token", default=os.environ.get("R2_TOKEN"))
    ap.add_argument(
        "--prompt-ids",
        default="capital-france,opposite-allowed",
        help="comma-separated prompt IDs",
    )
    args = ap.parse_args()

    try:
        import transformers  # noqa: F401
        import torch  # noqa: F401
    except ImportError as e:
        print(f"ERROR: missing dependency: {e}", file=sys.stderr)
        return 2

    try:
        from sklearn.utils.extmath import randomized_svd  # noqa: F401
    except ImportError:
        print("ERROR: scikit-learn not installed (needed for randomized SVD)", file=sys.stderr)
        return 2

    prompt_ids = {p.strip() for p in args.prompt_ids.split(",")}
    selected_prompts = [p for p in PROMPTS if p["id"] in prompt_ids]

    sketch_out = Path(args.sketch_out) if args.sketch_out else None

    prompts_with_id = [{**p, "modelId": args.model_id} for p in selected_prompts]
    observations = run_probe(
        hf_model_id=args.hf_model,
        hf_token=args.hf_token,
        prompts=prompts_with_id,
        sketch_out=sketch_out,
        r2_url=args.r2_upload_url,
        r2_token=args.r2_token,
        r2_base_url=args.r2_base_url,
        model_id=args.model_id,
    )

    out_path = Path(args.out)
    existing: list[dict] = []
    if out_path.exists():
        try:
            existing = json.loads(out_path.read_text()).get("observations", [])
        except Exception:
            pass
    ex_map = {(o["modelId"], o["promptId"]): i for i, o in enumerate(existing)}
    for obs in observations:
        key = (obs["modelId"], obs["promptId"])
        if key in ex_map:
            existing[ex_map[key]] = obs
        else:
            existing.append(obs)

    out_path.write_text(json.dumps({"observations": existing}, indent=2))
    print(f"[escape-probe] wrote {len(observations)} observation(s) → {out_path}", file=sys.stderr)
    return 0


if __name__ == "__main__":
    sys.exit(main())
